// Normalize input
const body = $json.body || $json;
const input = {
  experiment_id: body.experiment_id || `exp_${new Date().toISOString().slice(0,10)}_${Math.random().toString(36).slice(2,7)}`,
  lp_url: body.lp_url || '',
  control_headline: body.control_headline || '',
  control_subhead: body.control_subhead || '',
  target_persona: body.target_persona || 'general',
  variants_count: parseInt(body.variants_count || 2),
  hypothesis: body.hypothesis || '',
  created_at: new Date().toISOString(),
};

if (!input.lp_url || !input.control_headline) {
  throw new Error('lp_url and control_headline are required');
}
return [{ json: input }];

// Extract visible text (for product context)
const raw = $input.first().json.data || $input.first().json;
const html = typeof raw === 'string' ? raw : String(raw);
const text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 4000);
const input = $('Validate Input').first().json;
return [{ json: { ...input, lp_text: text } }];

