const raw = $json.message?.content?.[0]?.text || $json.content || $json.text;
let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw.replace(/^```json\s*|\s*```$/g, '')) : raw;
} catch (e) {
  return [];
}
const ctx = $('Extract LP Text').item.json;
const variants = parsed.variants || [];

// Build rows for CampaignMetrics: 1 row per variant (control + treatments)
const now = new Date().toISOString().slice(0, 10);
const rows = [];

// Control
rows.push({
  json: {
    name: `${ctx.experiment_id} — Control`,
    variant_id: 'control',
    experiment_id: ctx.experiment_id,
    headline: ctx.control_headline,
    subhead: ctx.control_subhead,
    hook_angle: 'control',
    why: 'Current production',
    lp_url: ctx.lp_url,
    date: now,
  }
});

for (const v of variants) {
  rows.push({
    json: {
      name: `${ctx.experiment_id} — Variant ${v.variant_id}`,
      variant_id: v.variant_id,
      experiment_id: ctx.experiment_id,
      headline: v.headline,
      subhead: v.subhead || '',
      hook_angle: v.hook_angle,
      why: v.why,
      lp_url: ctx.lp_url,
      date: now,
    }
  });
}
return rows;

const rows = $input.all().map(i => i.json);
const ctx = $('Extract LP Text').first().json;

let text = `🧪 *새 LP A/B 실험 준비*\n` +
  `*ID*: \`${ctx.experiment_id}\`\n` +
  `*LP*: <${ctx.lp_url}|${ctx.lp_url}>\n` +
  `*Persona*: ${ctx.target_persona}\n` +
  `*Hypothesis*: ${ctx.hypothesis || '(none)'}\n\n` +
  `*Variants*:\n`;
rows.forEach(r => {
  const isControl = r.variant_id === 'control';
  text += `${isControl ? '🔵' : '🟢'} *${isControl ? 'Control' : r.variant_id}* — \"${r.headline}\"\n`;
  if (r.subhead) text += `   _${r.subhead}_\n`;
  if (!isControl) text += `   각도: ${r.hook_angle}\n`;
});
text += `\nNotion CampaignMetrics에서 experiment_id 필터로 조회 가능. 검토 후 LP에 배포.`;
return [{ json: { text } }];
